module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

reg [15:0] result_reg;
reg [15:0] SR;
reg [7:0] neg_divisor;
reg [7:0] dividend_temp;
reg [7:0] divisor_temp;
reg [3:0] cnt;
reg start_cnt;
reg res_valid_reg;
assign res_valid = res_valid_reg;
assign result = result_reg;
always @(posedge clk or posedge rst) begin
    if(rst)begin
        res_valid_reg <= 1'b0;
    end else if(cnt == 8 && res_valid_reg != 1'b1)begin
        res_valid_reg <= 1'b1;
    end else if(res_valid_reg == 1'b1 && res_ready == 1'b1)begin
        res_valid_reg <= 1'b0;
    end else begin
        res_valid_reg <= res_valid_reg;
    end
end
always @(posedge clk) begin
    if(opn_valid == 1'b1 && res_valid_reg == 1'b0)begin
        dividend_temp <= dividend;
        divisor_temp <= divisor;
    end else begin
        dividend_temp <= dividend_temp;
        divisor_temp <= divisor_temp;
    end
end
always @(posedge clk) begin
    if(opn_valid == 1'b1 && res_valid_reg == 1'b0)begin
        if(sign == 1'b1)begin
            SR <= {dividend[7], dividend} << 1;
        end else begin
            SR <= dividend << 1;
        end
    end else if(start_cnt == 1'b1)begin
        if(SR[7:0] >= divisor_temp)begin
            SR <= {SR[7:0] - divisor_temp, SR[15:8]};
        end else begin
            SR <= {SR[7:0], SR[15:8]};
        end
        if(cnt == 8)begin
            cnt <= 1'b0;
            start_cnt <= 1'b0;
        end else begin
            cnt <= cnt + 1'b1;
        end
    end else begin
        cnt <= cnt;
        start_cnt <= start_cnt;
    end
end
always @(posedge clk) begin
    if(opn_valid == 1'b1 && res_valid_reg == 1'b0)begin
        if(divisor[7] == 1'b1)begin
            neg_divisor <= ~divisor + 1;
        end else begin
            neg_divisor <= divisor;
        end
    end else begin
        neg_divisor <= neg_divisor;
    end
end
always @(posedge clk) begin
    if(opn_valid == 1'b1 && res_valid_reg == 1'b0)begin
        if(sign == 1'b1)begin
            result_reg <= {SR[15:8], SR[7:0]};
        end else begin
            result_reg <= {SR[15:8], SR[7:0]};
        end
    end else begin
        result_reg <= result_reg;
    end
end
endmodule
